// interface `socket` over a channel: opcodes, a Service trait + dispatch, and a Client.
pub mod socket {
	use super::*;
	use crate::codec::{Reader, Sink, SliceWriter, Transport, VecWriter};
	use alloc::vec::Vec;

	pub const OP_SEND: u16 = 1;
	pub const OP_RECV: u16 = 2;
	pub const OP_CLOSE: u16 = 3;

	pub trait Service {
		fn send(&mut self, data: crate::codec::Buffer) -> Result<u32, Error>;
		fn recv(&mut self) -> Vec<Chunk>;
		fn close(&mut self) -> Result<(), Error>;
	}

	pub fn dispatch<S: Service>(service: &mut S, request: &[u8], request_handle: u64, out: &mut [u8], reply_handle: &mut u64) -> Option<usize> {
		let mut reader = Reader::with_handle(request, request_handle);
		let r = &mut reader;
		let op = r.u16()?;
		let corr = r.u32()?;
		let mut writer = SliceWriter::new(out);
		let w = &mut writer;
		w.u32(corr)?;
		match op {
			OP_SEND => {
				let data = {
					let len = r.u64()?;
					let handle = r.take_handle();
					crate::codec::Buffer { handle, len }
				};
				let result = service.send(data);
				match &result {
					Ok(v85) => {
						w.u8(1)?;
						w.u32(*v85)?;
					}
					Err(v86) => {
						w.u8(0)?;
						v86.write(w)?;
					}
				}
			}
			OP_CLOSE => {
				let result = service.close();
				match &result {
					Ok(v87) => {
						w.u8(1)?;
					}
					Err(v88) => {
						w.u8(0)?;
						v88.write(w)?;
					}
				}
			}
			_ => return None,
		}
		*reply_handle = writer.handle();
		Some(writer.pos())
	}

	pub fn recv_open<S: Service>(service: &mut S, request: &[u8]) -> Option<(u32, Vec<Chunk>)> {
		let mut reader = Reader::new(request);
		let r = &mut reader;
		let _op = r.u16()?;
		let corr = r.u32()?;
		let items = service.recv();
		Some((corr, items))
	}
	pub fn recv_frame(seq: u32, item: &Chunk, out: &mut [u8]) -> Option<usize> {
		let mut writer = SliceWriter::new(out);
		let w = &mut writer;
		w.u32(seq)?;
		item.write(w)?;
		Some(writer.pos())
	}
	pub fn recv_read(msg: &[u8]) -> Option<Chunk> {
		let mut reader = Reader::new(msg);
		let r = &mut reader;
		let _seq = r.u32()?;
		Some(Chunk::read(r)?)
	}

	pub struct Client<T: Transport> {
		transport: T,
		corr: u32,
	}

	impl<T: Transport> Client<T> {
		pub fn new(transport: T) -> Client<T> {
			Client { transport, corr: 0 }
		}
		pub fn into_transport(self) -> T {
			self.transport
		}
		fn next_corr(&mut self) -> u32 {
			let c = self.corr;
			self.corr = self.corr.wrapping_add(1);
			c
		}
		pub fn send(&mut self, data: &crate::codec::Buffer) -> Option<Result<u32, Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_SEND)?;
			w.u32(corr)?;
			w.set_handle(data.handle);
			w.u64(data.len)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = Reader::with_handle(&reply, reply_handle);
			let r = &mut reader;
			if r.u32()? != corr {
				return None;
			}
			Some(if r.u8()? != 0 { Ok(r.u32()?) } else { Err(Error::read(r)?) })
		}
		pub fn recv(&mut self) -> Option<u64> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_RECV)?;
			w.u32(corr)?;
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, 0)?;
			let mut reader = Reader::new(&reply);
			let r = &mut reader;
			if r.u32()? != corr || reply_handle == 0 {
				return None;
			}
			Some(reply_handle)
		}
		pub fn close(&mut self) -> Option<Result<(), Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_CLOSE)?;
			w.u32(corr)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = Reader::with_handle(&reply, reply_handle);
			let r = &mut reader;
			if r.u32()? != corr {
				return None;
			}
			Some(if r.u8()? != 0 { Ok(()) } else { Err(Error::read(r)?) })
		}
	}
}

#[derive(Clone, Debug, PartialEq)]
pub struct Chunk {
	pub data: Vec<u8>,
}

impl Chunk {
	pub fn encode(&self, out: &mut [u8]) -> Option<usize> {
		let mut w = SliceWriter::new(out);
		self.write(&mut w)?;
		Some(w.pos())
	}
	pub fn encode_vec(&self) -> Vec<u8> {
		let mut w = VecWriter::new();
		let _ = self.write(&mut w);
		w.into_inner()
	}
	pub fn decode(bytes: &[u8]) -> Option<Chunk> {
		Chunk::read(&mut Reader::new(bytes))
	}
	pub(crate) fn write<W: Sink>(&self, w: &mut W) -> Option<()> {
		if self.data.len() > u16::MAX as usize {
			return None;
		}
		w.u16(self.data.len() as u16)?;
		for v89 in self.data.iter() {
			w.u8(*v89)?;
		}
		Some(())
	}
	pub(crate) fn read(r: &mut Reader) -> Option<Chunk> {
		let data = {
			let v90 = r.u16()? as usize;
			let mut v91 = Vec::new();
			for _ in 0..v90 {
				v91.push(r.u8()?);
			}
			v91
		};
		Some(Chunk { data })
	}
}

