		match op {
			OP_ACCEPT => {
				let result = service.accept();
				match &result {
					Ok(v92) => {
						w.u8(1)?;
						w.set_handle(*v92);
						w.u32(0)?;
					}
					Err(v93) => {
						w.u8(0)?;
						v93.write(w)?;
					}
				}
			}
			_ => return None,
		}
